return $input.all().map(item => {
  const rawProduto = item.json.Produto || '';
  const ponto = item.json['Ponto de Atendimento'] || '';

  // 1. FUNÇÃO DE NORMALIZAÇÃO DE TEXTO
  function normalize(str) {
    if (!str || typeof str !== 'string') return '';
    return str.trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, '');
  }

  const produtoNorm = normalize(rawProduto);

  // 2. PADRONIZAÇÃO DO PRODUTO
  let ProdutoPadronizado = '';
  let tipo = '';
  let nivel = '';

  if (produtoNorm.includes('e-cpf a3') || produtoNorm.includes('certificado a3 pf') || produtoNorm.includes('cedula de identidade medica')) {
    ProdutoPadronizado = 'e-CPF A3'; tipo = 'CPF'; nivel = 'A3';
  } else if (produtoNorm.includes('e-cpf a1') || produtoNorm.includes('certificado a1 pf')) {
    ProdutoPadronizado = 'e-CPF A1'; tipo = 'CPF'; nivel = 'A1';
  } else if (produtoNorm.includes('e-cnpj a1 mercado livre') || produtoNorm.includes('mercado livre') || produtoNorm.includes('pequenas empresas') || produtoNorm.includes('bling')) {
    ProdutoPadronizado = 'e-CNPJ A1 PME'; tipo = 'CNPJ'; nivel = 'A1';
  } else if (produtoNorm.includes('certificado a1 pj') || produtoNorm.includes('nf e a1') || produtoNorm.includes('ac certisign multipla')) {
    ProdutoPadronizado = 'e-PJ A1'; tipo = 'PJ'; nivel = 'A1';
  } else {
    const regex = /(e-cpf|e-cnpj|e-pj|e-pf)[\s-]*(a1|a3)/i;
    const match = produtoNorm.match(regex);
    if (match) {
      const tipoBruto = match[1].toUpperCase().replace('E-PF', 'e-CPF').replace('E-PJ', 'e-PJ');
      const nivelBruto = match[2].toUpperCase();
      ProdutoPadronizado = `${tipoBruto} ${nivelBruto}`;
      tipo = tipoBruto.includes('CPF') ? 'CPF' : 'CNPJ';
      nivel = nivelBruto;
    } else {
      if (produtoNorm.includes('cpf') || produtoNorm.includes('pf')) {
        ProdutoPadronizado = 'e-CPF A1'; tipo = 'CPF'; nivel = 'A1';
      } else if (produtoNorm.includes('pj')) {
        ProdutoPadronizado = 'e-PJ A1'; tipo = 'PJ'; nivel = 'A1';
      } else {
        ProdutoPadronizado = 'e-CNPJ A1'; tipo = 'CNPJ'; nivel = 'A1';
      }
    }
  }

  // 3. IDENTIFICAÇÃO DO PONTO E AGENTE
  const normalizedPonto = normalize(ponto);
  let vendorKey = 'DEFAULT';
  let agente = 'Alexandre';

  if (normalizedPonto.includes('prado') || normalizedPonto.includes('bh')) {
    vendorKey = 'AR CERTIFAST - PRADO BH/MG';
    agente = 'Isabella';
  } else if (normalizedPonto.includes('andromeda')) {
    vendorKey = 'ANDROMEDA';
    agente = 'Rogério';
  }

  // 4. MAPEAMENTO DE LINKS
  const LINK_MAPPINGS = {
    'ANDROMEDA': {
      'e-PJ A1': { certifast: 'https://gestaoar.certisign.com.br/GestaoAR/cliente/produto/inicio?produto=ACMA1PJHV2&grupo=CPBRB&cliente_AR=ACMVR&origem=1&cod_rev=71210', certiid: 'https://parceiro.gestaoar.shop/arcertiid/shop/produto/76ddde28-bf23-41b3-90d0-a354c2330134' },
