      'e-CNPJ A3': { certifast: 'https://gestaoar.certisign.com.br/GestaoAR/cliente/produto/inicio?produto=SRFA3PJSCHV2&grupo=CPBRB&cliente_AR=CRSNT&origem=1&cod_rev=71210', certiid: 'https://parceiro.gestaoar.shop/arcertiid/shop/produto/339815af-afde-40af-8cb0-bf3054ae9fe3' },
      'e-CNPJ A1': { certifast: 'https://gestaoar.certisign.com.br/GestaoAR/cliente/produto/inicio?produto=SRFA1PJHV2&grupo=CPBRB&cliente_AR=CRSNT&origem=1&cod_rev=71210', certiid: 'https://parceiro.gestaoar.shop/arcertiid/shop/produto/8749346c-aa72-42f7-8fb1-78153ee7a7fe' },
      'e-CPF A3': { certifast: 'https://gestaoar.certisign.com.br/GestaoAR/cliente/produto/inicio?produto=SRFA3PFSMHV2&grupo=CPBRB&cliente_AR=CRSNT&origem=1&cod_rev=71210', certiid: 'https://parceiro.gestaoar.shop/arcertiid/shop/produto/62d1e0a3-a509-41b8-861b-f37f28a5dcda' },
      'e-CPF A1': { certifast: 'https://gestaoar.certisign.com.br/GestaoAR/cliente/produto/inicio?produto=SRFA1PFHV2&grupo=CPBRB&cliente_AR=CRSNT&origem=1&cod_rev=71210', certiid: 'https://parceiro.gestaoar.shop/arcertiid/shop/produto/4ee57e38-826b-4d5f-9efc-ffa76e51a803' }
    },
    'AR CERTIFAST - PRADO BH/MG': {
      'e-PJ A1': { certiid: 'https://parceiro.gestaoar.shop/arcertiid/bh/produto/76ddde28-bf23-41b3-90d0-a354c2330134' },
      'e-CNPJ A1 PME': { certiid: 'https://parceiro.gestaoar.shop/arcertiid/bh/produto/890f8cc5-f102-4a98-931d-1375c0266668' },
